jQuery(document).ready(function($) {
    function getPostContent() {
        if (wp.data && wp.data.select('core/editor')) {
            return wp.data.select('core/editor').getEditedPostAttribute('content');
        } else {
            return $('#content').val();
        }
    }

    function getPostTitle() {
        if (wp.data && wp.data.select('core/editor')) {
            return wp.data.select('core/editor').getEditedPostAttribute('title');
        } else {
            return $('#title').val();
        }
    }

    $('#quorlyx-generate-schema').on('click', function() {
        var $button = $(this);
        var $spinner = $button.siblings('.spinner');
        var $resultsDiv = $('#quorlyx-meta-box-results');
        $button.prop('disabled', true);
        $spinner.addClass('is-active');
        $resultsDiv.hide();
        $.ajax({
            url: quorlyxEditor.restUrl + 'generate-schema',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxEditor.nonce);
            },
            data: {
                post_id: quorlyxEditor.postId
            }
        }).done(function(response) {
            $('#quorlyx-schema-preview pre').text(response.schema);
            $resultsDiv.html('<p style="color:green;">Schema generated and saved successfully!</p>').show();
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            $resultsDiv.html('<p style="color:red;">Error: ' + message + '</p>').show();
        }).always(function() {
            $button.prop('disabled', false);
            $spinner.removeClass('is-active');
        });
    });

    $('#quorlyx-suggest-links').on('click', function() {
        var $button = $(this);
        var $spinner = $button.siblings('.spinner');
        var $resultsDiv = $('#quorlyx-meta-box-results');
        $button.prop('disabled', true);
        $spinner.addClass('is-active');
        $resultsDiv.hide();
        $.ajax({
            url: quorlyxEditor.restUrl + 'suggest-links',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxEditor.nonce);
            },
            data: {
                post_id: quorlyxEditor.postId
            }
        }).done(function(response) {
            var suggestionsHTML = '<strong>Suggestions:</strong><ul style="margin-top:5px; padding-left: 15px;">';
            var lines = response.suggestions.split('\n');
            lines.forEach(function(line) {
                if (line.trim()) {
                    var parts = line.split('->');
                    if (parts.length === 2) {
                        suggestionsHTML += '<li style="margin-bottom: 5px;">"' + $.trim(parts[0]) + '" &rarr; <a href="' + $.trim(parts[1]) + '" target="_blank">' + $.trim(parts[1]) + '</a></li>';
                    } else {
                        suggestionsHTML += '<li style="margin-bottom: 5px;">' + line + '</li>';
                    }
                }
            });
            suggestionsHTML += '</ul>';
            $resultsDiv.html(suggestionsHTML).show();
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            $resultsDiv.html('<p style="color:red;">Error: ' + message + '</p>').show();
        }).always(function() {
            $button.prop('disabled', false);
            $spinner.removeClass('is-active');
        });
    });

    $('#quorlyx-improve-seo').on('click', function() {
        var $button = $(this);
        var $spinner = $button.siblings('.spinner');
        var $resultsDiv = $('#quorlyx-meta-box-results');
        $button.prop('disabled', true);
        $spinner.addClass('is-active');
        $resultsDiv.hide();
        $.ajax({
            url: quorlyxEditor.restUrl + 'suggest-seo-improvements',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxEditor.nonce);
            },
            data: {
                post_id: quorlyxEditor.postId
            }
        }).done(function(response) {
            var analysisHtml = $('<div/>').text(response.analysis).html().replace(/\n/g, '<br>');
            $resultsDiv.html('<strong>SEO Improvement Plan:</strong><div style="margin-top:6px; white-space:normal;">' + analysisHtml + '</div>').show();
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            $resultsDiv.html('<p style="color:red;">Error: ' + message + '</p>').show();
        }).always(function() {
            $button.prop('disabled', false);
            $spinner.removeClass('is-active');
        });
    });
});